"use client";

import React, { useState, useMemo } from 'react';
import { 
  Search, Trophy, Home, List, Users, 
  ChevronRight, Crown, Activity, 
  ChevronLeft, Copy, Shield, X, Swords, Crosshair,
  Zap, Anchor, Target, Flame
} from 'lucide-react';
import playersData from '../data/players.json';

export default function McTierUltimate() {
  const [search, setSearch] = useState("");
  const [activeTab, setActiveTab] = useState("Overall");
  const [isExpanded, setIsExpanded] = useState(false);
  const [copied, setCopied] = useState(false);
  const [selectedPlayer, setSelectedPlayer] = useState<any | null>(null);

  // --- EXPANDED GAMEMODES LIST ---
  const kitTabs = [
    "Overall", "Crystal", "Sword", "UHC", "Axe", 
    "Neth Pot", "SMP", "Tank", "Anchor", "Boxing"
  ];

  const handleCopy = () => {
    navigator.clipboard.writeText("play.nordenmc.com");
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getTierStyles = (tier: string) => {
    const t = tier?.toUpperCase();
    if (t?.includes('HT1')) return 'text-red-500 border-red-500/50 bg-red-500/10 shadow-[0_0_20px_rgba(239,68,68,0.3)]';
    if (t?.includes('LT1')) return 'text-cyan-400 border-cyan-500/50 bg-cyan-500/10 shadow-[0_0_20px_rgba(6,182,212,0.3)]';
    if (t?.includes('T2')) return 'text-purple-400 border-purple-500/40 bg-purple-500/10 shadow-[0_0_15px_rgba(168,85,247,0.2)]';
    if (t?.includes('T3')) return 'text-emerald-400 border-emerald-500/40 bg-emerald-500/10';
    return 'text-gray-400 border-white/10 bg-white/5';
  };

  const filteredPlayers = useMemo(() => {
    const data = Array.isArray(playersData) ? playersData : [];
    return data
      .filter((player: any) => {
        const matchesSearch = player.name?.toLowerCase().includes(search.toLowerCase());
        const matchesTab = activeTab === "Overall" || player.kit === activeTab;
        return matchesSearch && matchesTab;
      })
      .sort((a: any, b: any) => (a.rank || 0) - (b.rank || 0));
  }, [search, activeTab]);

  return (
    <div className="flex min-h-screen bg-[#050507] text-[#e1e1e3] font-sans overflow-x-hidden selection:bg-cyan-500/30 relative">
      
      {/* --- STATS GUI MODAL --- */}
      {selectedPlayer && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-md z-[200] flex items-center justify-center p-4" onClick={() => setSelectedPlayer(null)}>
          <div className="bg-[#0a0a0d] border border-cyan-500/30 rounded-[2.5rem] w-full max-w-2xl overflow-hidden shadow-[0_0_80px_rgba(6,182,212,0.2)]" onClick={e => e.stopPropagation()}>
            <div className="relative h-40 bg-gradient-to-b from-cyan-900/20 to-transparent border-b border-white/5 flex items-end p-10">
              <button onClick={() => setSelectedPlayer(null)} className="absolute top-8 right-8 text-gray-500 hover:text-white transition-colors"><X size={32} /></button>
              <img src={`https://mc-heads.net/avatar/${selectedPlayer.name}/150`} className="w-28 h-28 rounded-3xl border-4 border-[#0a0a0d] bg-[#0f0f13] translate-y-12 shadow-2xl" alt="" />
            </div>
            <div className="p-10 pt-16">
              <div className="flex justify-between items-start mb-10">
                <div>
                  <h2 className="text-4xl font-black italic tracking-tighter uppercase">{selectedPlayer.name}</h2>
                  <p className="text-cyan-500 font-bold tracking-[0.3em] uppercase text-xs mt-2 flex items-center gap-2">
                    <Zap size={14} fill="currentColor" /> Tiered Contender
                  </p>
                </div>
                <div className={`px-10 py-4 rounded-2xl border ${getTierStyles(selectedPlayer.tier)}`}>
                  <span className="text-4xl font-black italic tracking-tighter">{selectedPlayer.tier}</span>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/[0.03] border border-white/5 p-6 rounded-3xl">
                  <p className="text-[10px] font-black uppercase tracking-widest text-gray-500 mb-1">Primary Discipline</p>
                  <p className="text-xl font-bold text-white">{selectedPlayer.kit}</p>
                </div>
                <div className="bg-white/[0.03] border border-white/5 p-6 rounded-3xl">
                  <p className="text-[10px] font-black uppercase tracking-widest text-gray-500 mb-1">Global Position</p>
                  <p className="text-xl font-bold text-cyan-400">#{selectedPlayer.rank}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* --- SIDEBAR --- */}
      <aside className={`hidden lg:flex flex-col py-8 border-r border-white/5 bg-[#08080a] sticky top-0 h-screen transition-all duration-500 ease-in-out z-[100] ${isExpanded ? 'w-64 px-6' : 'w-24 items-center'}`}>
        <div onClick={() => setIsExpanded(!isExpanded)} className="mb-12 cursor-pointer text-cyan-500 bg-cyan-500/10 p-4 rounded-2xl border border-cyan-500/20 hover:shadow-[0_0_30px_rgba(6,182,212,0.3)] transition-all">
          {isExpanded ? <ChevronLeft size={24} /> : <Trophy size={24} />}
        </div>
        <nav className="flex flex-col gap-10 text-gray-600 w-full">
          {[{ icon: <Home size={22} />, label: "Portal" }, { icon: <List size={22} />, label: "Rankings", active: true }, { icon: <Users size={22} />, label: "Staff" }].map((item, idx) => (
            <div key={idx} className={`flex items-center gap-5 cursor-pointer hover:text-cyan-400 transition-colors group ${isExpanded ? 'px-2' : 'justify-center'}`}>
              <div className={item.active ? 'text-cyan-500' : ''}>{item.icon}</div>
              {isExpanded && <span className={`font-black uppercase tracking-widest text-[11px] ${item.active ? 'text-white' : ''}`}>{item.label}</span>}
            </div>
          ))}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col min-w-0">
        <div className="bg-cyan-500/10 border-b border-cyan-500/20 py-3 px-8 flex items-center justify-center gap-8 text-[10px] font-black uppercase tracking-[0.3em] text-cyan-400 shadow-[0_0_30px_rgba(6,182,212,0.1)]">
          <div className="flex items-center gap-3"><div className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse" /> Network Secured</div>
          <div className="w-px h-3 bg-cyan-500/20" />
          <div className="flex items-center gap-2 cursor-pointer hover:text-white transition-all group" onClick={handleCopy}>
             {copied ? "COPIED" : "IP: PLAY.NORDENMC.COM"} <Copy size={12} />
          </div>
        </div>

        <header className="h-24 border-b border-white/5 bg-[#050507]/80 backdrop-blur-3xl sticky top-0 z-40 px-10 flex items-center justify-between">
          <h1 className="text-3xl font-black italic tracking-tighter text-white uppercase">Norden<span className="text-cyan-500">MC</span></h1>
          <div className="relative w-80 md:w-[400px] group">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-cyan-500 transition-colors" size={18} />
            <input type="text" placeholder="Locate contender..." className="w-full bg-[#0a0a0d] border border-white/5 rounded-2xl py-3.5 pl-14 pr-6 outline-none focus:border-cyan-500/40 transition-all text-xs font-bold uppercase tracking-widest" value={search} onChange={(e) => setSearch(e.target.value)} />
          </div>
        </header>

        <main className="p-8 md:p-14 max-w-7xl mx-auto w-full">
          
          {/* --- TOP 3 PODIUM --- */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
            {filteredPlayers.slice(0, 3).map((p, i) => (
              <div key={p.name} onClick={() => setSelectedPlayer(p)} className="relative overflow-hidden bg-[#0a0a0d] border border-white/5 p-8 rounded-[2.5rem] shadow-2xl hover:border-cyan-500/40 transition-all duration-500 group cursor-pointer hover:-translate-y-2">
                <div className="flex items-center gap-6">
                  <div className="relative">
                    <img src={`https://mc-heads.net/avatar/${p.name}/100`} className="w-20 h-20 rounded-2xl border border-white/10 group-hover:scale-105 transition-transform" alt="" />
                    <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-green-500 border-4 border-[#0a0a0d] rounded-full"></div>
                  </div>
                  <div>
                    <h3 className="font-black text-2xl italic uppercase text-white">{p.name}</h3>
                    <p className="text-[10px] font-black tracking-[.2em] text-cyan-500/60 uppercase mt-1">#0{p.rank} Global</p>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* --- EXPANDED FILTERS --- */}
          <div className="flex flex-wrap gap-3 mb-12 bg-[#0a0a0d]/50 p-2 rounded-2xl border border-white/5 w-fit">
            {kitTabs.map((tab) => (
              <button key={tab} onClick={() => setActiveTab(tab)} className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-cyan-500 text-black shadow-[0_0_20px_rgba(6,182,212,0.5)]' : 'text-gray-500 hover:text-gray-200'}`}>
                {tab}
              </button>
            ))}
          </div>

          {/* --- MAIN LIST --- */}
          <div className="bg-[#0a0a0d] border border-white/5 rounded-[3rem] overflow-hidden shadow-2xl">
            <div className="grid grid-cols-12 gap-4 p-8 bg-white/[0.01] border-b border-white/5 text-[10px] text-gray-600 font-black uppercase tracking-[0.4em]">
              <div className="col-span-1 pl-4">ID</div>
              <div className="col-span-7">Contender Identification</div>
              <div className="col-span-4 text-right pr-10">Combat Tier</div>
            </div>

            <div className="divide-y divide-white/[0.02]">
              {filteredPlayers.map((player: any) => (
                <div key={player.name} onClick={() => setSelectedPlayer(player)} className="grid grid-cols-12 gap-4 p-7 md:p-8 items-center hover:bg-white/[0.01] transition-all group cursor-pointer">
                  <div className="col-span-1 text-4xl font-black italic text-gray-900 group-hover:text-cyan-500/20 transition-colors pl-2">{player.rank.toString().padStart(2, '0')}</div>
                  <div className="col-span-7 flex items-center gap-7">
                    <img src={`https://mc-heads.net/avatar/${player.name}/100`} className="w-16 h-16 rounded-2xl border border-white/5 group-hover:scale-110 transition-all duration-500 shadow-xl" alt="" />
                    <div>
                      <div className="font-black text-2xl tracking-tighter text-white/90 group-hover:text-white flex items-center gap-3 italic uppercase">{player.name} <span className="text-[9px] not-italic bg-white/5 px-2 py-0.5 rounded text-gray-500 border border-white/5">AS</span></div>
                      <div className="flex items-center gap-2 text-[10px] text-gray-500 font-black uppercase mt-2 tracking-widest"><Activity size={12} className="text-cyan-500" /> {player.kit} Spec</div>
                    </div>
                  </div>
                  <div className="col-span-4 flex justify-end items-center gap-8 pr-6">
                    <div className={`border px-8 py-3 rounded-2xl transition-all duration-500 group-hover:scale-110 ${getTierStyles(player.tier)}`}>
                      <span className="text-2xl font-black italic tracking-tighter">{player.tier}</span>
                    </div>
                    <ChevronRight size={24} className="text-gray-800 group-hover:text-cyan-500 group-hover:translate-x-2 transition-all" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}